// Filtrar dietas que necesitan recordatorio hoy
const items = $input.all();
const now = new Date();
now.setUTCHours(0, 0, 0, 0); // normalizar a inicio del día UTC
const result = [];

for (const item of items) {
  const d = item.json;
  if (!d.fecha_envio) continue;
  const fe = new Date(d.fecha_envio);
  fe.setUTCHours(0, 0, 0, 0); // normalizar a inicio del día UTC
  fe.setUTCDate(fe.getUTCDate() + 3); // fecha efectiva = 3 días de margen para el cliente
  const days = Math.floor((now - fe) / (1000 * 60 * 60 * 24));

  if (days >= 13 && days <= 18 && !d.email_dia14_enviado) {
    result.push({ json: { ...d, tipo_recordatorio: '2sem', dias_desde_envio: days } });
  } else if (days >= 29 && days <= 38 && !d.email_dia28_enviado) {
    result.push({ json: { ...d, tipo_recordatorio: '1mes', dias_desde_envio: days } });
  }
}

return result.length > 0 ? result : [{ json: { __empty: true } }];

