  // Estrategia 2: objeto agrupado
  const f2 = fields.find(f => f.type === 'HIDDEN_FIELDS' && f.value && typeof f.value === 'object' && !Array.isArray(f.value));
  if (f2 && f2.value[label] !== undefined) return f2.value[label];

  return null;
};

